fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    let sorted_nums: Vec<i64> = nums.clone();
    sorted_nums.sort_unstable();
    let mut max_k = 0;

    for k in 0..n {
        let mut current = nums.clone();
        let mut visited = vec![false; n];

        let mut sorted = true;
        for i in 0..n {
            if visited[i] {
                continue;
            }

            let mut found = false;
            for j in i..n {
                if !visited[j] && (current[i] & current[j]) == k as i64 {
                    current.swap(i, j);
                    visited[j] = true;
                    found = true;
                    break;
                }
            }

            if !found {
                sorted = false;
                break;
            }
        }

        if sorted && current == sorted_nums {
            max_k = k as i64;
        }
    }

    max_k
}
